SELECT model, price
FROM snowboards
WHERE price = (SELECT MAX(price) FROM snowboards);

SELECT model, price
FROM snowboards
ORDER BY price ASC;

SELECT DISTINCT brand
FROM snowboards
ORDER BY brand ASC;

SELECT price, description, model
FROM snowboards
WHERE price IN (SELECT MIN(price) FROM snowboards UNION SELECT MAX(price) FROM snowboards);

SELECT brand, model, price
FROM snowboards
ORDER BY price ASC;
